import{_ as a,v as t,f as r,i as o}from"./chunks/framework.jfF5glnW.js";const h=JSON.parse('{"title":"Week 12 | 设计思维与项目整理","description":"","frontmatter":{"title":"Week 12 | 设计思维与项目整理","date":"2026-05-19T00:00:00.000Z","tags":["课程周志","设计思维","项目实践"],"cover":"/code2real_blog/posts/week12/brain.jpg"},"headers":[],"relativePath":"posts/week12.md","filePath":"posts/week12.md"}'),s={name:"posts/week12.md"};function p(i,e,n,l,_,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>第十二周围绕设计思维展开。本周重点不是学习单一工具，而是整理从问题发现到方案迭代的设计流程。</p><hr><img src="/code2real_blog/posts/week12/brain.jpg" alt="Week 12 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周主要学习设计思维的基本方法，包括理解需求、定义问题、提出方案、制作原型和测试反馈。与前面具体工具训练相比，设计思维更关注为什么要做、为谁做，以及方案是否真正解决问题。</p><p>课程中强调不能一开始就急着进入制作阶段。无论是建模、PCB 还是嵌入式项目，如果没有先明确使用场景和约束条件，后续很容易出现“东西做出来了，但问题没有解决”的情况。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先围绕已有课程项目进行回顾，分析每个作品的目标、使用对象和实际限制。比如 PCB 设计不仅要能工作，还要考虑焊接、展示和主题表达；嵌入式作品不仅要能运行，还要考虑控制方式是否直观、系统是否稳定。</p><p>随后尝试把项目整理成更完整的设计流程：先描述问题，再列出需求和限制，接着提出可执行方案，最后根据测试结果修改。这个过程比单纯完成作品更慢，但能帮助发现很多之前被忽略的细节。</p>',9)])])}const k=a(s,[["render",p]]);export{h as __pageData,k as default};
